// TypeScript implementation for Abstract Classes
interface AbstractClassesPayload {
  id: number;
  title: string;
  status: 'active' | 'pending';
}

function processAbstractClasses(item: AbstractClassesPayload): string {
  return `[${item.id}] ${item.title}: ${item.status}`;
}

console.log(processAbstractClasses({ id: 1, title: 'Abstract Classes', status: 'active' }));

